INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.operation.primary_tillage','choice','attr.agroscope.operation',NULL,NULL,NULL,NULL,'{"en":"Primary Tillage"}',NULL,'{"description":"Primary tillage is a loosening, mixing or inverting form of cultivation with a cultivation depth between 15 cm and 35 cm. Primary tillage takes place prior to seedbed preparation and sowing.","source":"KTBL (2020)","source_category":"tillage"}','core',1,1000,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.operation.seedbed_preparation','choice','attr.agroscope.operation',NULL,NULL,NULL,NULL,'{"en":"Seedbed Preparation"}',NULL,'{"description":"Seedbed preparation or secondary tillage is limited to an operation depth of 5-10 cm. The seed horizon\nis crumbled finely, loosened and reconsolidated to ensure optimal seed germination.","source":"KTBL (2020)","source_category":"tillage"}','core',1,1001,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.operation.stubble_cultivation','choice','attr.agroscope.operation',NULL,NULL,NULL,NULL,'{"en":"Stubble Cultivation"}',NULL,'{"description":"Stubble cultivation is only a shallow cultivation method to loosen, mix or invert the soil after harvesting to promote the emergence of volunteer grain and weed seeds, with a cultivation depth of up to 15 cm. It is assumed that the implements are used as intended. Within the non-inversion method, all further operations with an operation depth of more than 10 cm represent primary tillage.","source":"KTBL (2020)","source_category":"tillage"}','core',1,1002,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.operation.sowing_cover_crop','choice','attr.agroscope.operation',NULL,NULL,NULL,NULL,'{"en":"Sowing Cover Crop"}',NULL,'{"description":"Sowing is the defined placement of seed at an optimal depth for the type of cover crop.","source":"KTBL (2020)","source_category":"sowing"}','core',1,1003,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.operation.sowing_main_crop','choice','attr.agroscope.operation',NULL,NULL,NULL,NULL,'{"en":"Sowing Main Crop"}',NULL,'{"description":"Sowing is the defined placement of seed at an optimal depth for the type of main crop.","source":"KTBL (2020)","source_category":"sowing"}','core',1,1004,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.operation.organic_fertilization','choice','attr.agroscope.operation',NULL,NULL,NULL,NULL,'{"en":"Organic Fertilization"}',NULL,'{"description":"Organic fertilizer: a carbon-rich fertilizer derived from organic materials, including treated or untreated livestock manures, compost, vermicompost, sewage sludge and other organic materials or mixed materials used to supply nutrients to soils.","source":"AGROVOC","source_category":"fertilizer_application"}','core',1,1005,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.operation.mineral_fertilization','choice','attr.agroscope.operation',NULL,NULL,NULL,NULL,'{"en":"Mineral Fertilization"}',NULL,'{"description":"Inorganic fertilizer: a nutrient-rich fertilizer produced industrially by chemical processes, mineral extraction or by mechanical grinding.","source":"AGROVOC","source_category":"fertilizer_application"}','core',1,1006,0,'2026-07-12T00:00:00.000Z');
