INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.plough','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Plough"}',NULL,'{"descriptions":["Loosening and mixing, inversion primary tillage. Intensive soil cultivation, very little covering with plant residues on the surface. Also called moldboard plough."],"sources":["KTBL (2020)"]}','core',1,2000,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.plough_with_packer','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Plough With Packer"}',NULL,'{"descriptions":["Loosening and mixing, inversion primary tillage with consolidation and breaking of clods. Intensive soil cultivation, leaving very little covering with plant residues on the surface. Crumbling and consolidation through trailing packer."],"sources":["KTBL (2020)"]}','core',1,2001,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.spading_machine','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Spading Machine"}',NULL,'{"descriptions":["Loosening and mixing, non-inversion primary tillage. The implement reduces covering of the surface with organic residues by 85 %."],"sources":["KTBL (2020)"]}','core',1,2002,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.deep_tiller','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Deep Tiller"}',NULL,'{"descriptions":["Loosening and mixing, non-inversion primary tillage with driven tools. The implement reduces covering of the surface with organic residues by 85 %."],"sources":["KTBL (2020)"]}','core',1,2003,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.heavy_duty_cultivator','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Heavy Duty Cultivator"}',NULL,'{"descriptions":["Loosening and mixing, non-inversion primary tillage. The implement reduces covering of the surface with organic residues by 50-75 %. Also called chisel plough.","Loosening and mixing, non-inversion stubble cultivation (deep). The implement reduces covering of the surface with organic residues by 50-75 %. Also called chisel plough."],"sources":["KTBL (2020)"]}','core',1,2004,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.heavy_duty_cultivator_sweeps','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Heavy Duty Cultivator Sweeps"}',NULL,'{"descriptions":["Same as above, but with sweeps mounted at the chisel."],"sources":["Custom","KTBL (2020)"]}','core',1,2005,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.disk_harrow','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Disk Harrow"}',NULL,'{"descriptions":["Loosening and mixing, non-inversion primary tillage. The implement reduces covering of the surface with organic residues by 40-60 %.","Mixing, non-inversion stubble cultivation. The implement reduces covering of the surface with organic residues by 40-60 %."],"sources":["KTBL (2020)"]}','core',1,2006,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.strip_tiller','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Strip Tiller"}',NULL,'{"descriptions":["Partial strip-wise loosening, non-inversion primary tillage - strip-wise cultivation of the seed rows before sowing. Less than 50 % of the total area is cultivated. The implement reduces covering of the surface with organic residues by 60-70 %.","The seed horizon is partially strip-wise loosened and crumbled with towed, not driven implements and reconsolidated with a roller. The implement speed is equivalent to the driving speed. The implement reduces covering of the cultivated surface with organic residues by 50-60 %."],"sources":["KTBL (2020)"]}','core',1,2007,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.subsoiler','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Subsoiler"}',NULL,'{"descriptions":["The subsoiler is a primary tillage tool, that is similar to a chisel plow. It is typically designed to penetrate 30 to 55 cm deep to alleviate soil compaction."],"sources":["NRCS (2017)"]}','core',1,2008,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.paraplough','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Paraplough"}',NULL,'{"descriptions":["The purpose of the Paraplough is to loosen compacted soil layers 30 to 40 cm deep and still maintain high surface residue levels. The Paraplow lifts and fractures the soil."],"sources":["NRCS (2017)"]}','core',1,2009,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.separator','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Separator"}',NULL,'{"descriptions":["Operation to separate stones, typcially used for potatos"],"sources":["Custom"]}','core',1,2010,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.skim_plough','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Skim Plough"}',NULL,'{"descriptions":["Inversion stubble cultivation. Little covering with plant residues on the surface (on < 10 % of ground covering)."],"sources":["KTBL (2020)"]}','core',1,2011,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.seedbed_combination','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Seedbed Combination"}',NULL,'{"descriptions":[],"sources":[]}','core',1,2012,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.rotary_harrow','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Rotary Harrow"}',NULL,'{"descriptions":["The seed horizon is loosened and crumbled with driven implements operating around a vertical axis, and reconsolidated with a roller. The implement reduces covering of the surface with organic residues by 30 %. The implement speed is equivalent to the driving speed in interaction with the circumferential speed of 3-6 m/s. Tines are straight, trailed or \"on grip\". Also called rotary cultivator when tines are \"on grip\"."],"sources":["KTBL (2020)"]}','core',1,2013,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.tine_rotor','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Tine Rotor"}',NULL,'{"descriptions":["The seed horizon is loosened and crumbled with driven implements operating around the transverse axis and reconsolidated with a roller. The implement reduces covering of the surface with organic residues by 50-75 %. The implement speed is equivalent to the driving speed in interaction with the circumferential speed of 4-8 m/s."],"sources":["KTBL (2020)"]}','core',1,2014,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.tiller','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Tiller"}',NULL,'{"descriptions":["The seed horizon is loosened and crumbled with driven implements operating around the transverse axis, and reconsolidated with a roller. The implement reduces covering of the surface with organic residues by 50-75 %. The implement speed is equivalent to the driving speed in interaction with the circumferential speed of 4-8 m/s"],"sources":["KTBL (2020)"]}','core',1,2015,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.bedder','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Bedder"}',NULL,'{"descriptions":["Operation to form dams or beds, e.g. for potatos or carotts"],"sources":["Custom"]}','core',1,2016,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.mulching','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Mulching"}',NULL,'{"descriptions":["Mulching involves shredding of above-ground organic material like stubbles, grasses or cover crops and covering the soil with the shredded material without any intervention in the soil."],"sources":["Custom"]}','core',1,2017,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.tine_weeder','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Tine Weeder"}',NULL,'{"descriptions":["Mixing, very shallow stubble cultivation. Even spreading of the straw covering and unroots weeds. The implement reduces covering of the surface with organic residues by 5 %."],"sources":["KTBL (2020)"]}','core',1,2018,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.rotary_weeder','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Rotary Weeder"}',NULL,'{"descriptions":["Mixing, very shallow stubble cultivation with a rotating device. Even spreading of the straw covering and unrooting weeds."],"sources":["Custom"]}','core',1,2019,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.ring_cutter','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Ring Cutter"}',NULL,'{"descriptions":["Loosening and mixing, non-inversion stubble cultivation. The implement reduces covering of the surface with organic residues by 10 %"],"sources":["KTBL (2020)"]}','core',1,2020,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.roller','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Roller"}',NULL,'{"descriptions":["Rollers firm the seed bed or consolidate loose soil. This contributes to better seed soil contact and is important for establishment of small seeded crops like forages.","Roller firm the seed bed or recompact loose soil. This contributes to better seed soil contact and is important for establishment of small seeded crops like forages.","Use of a roller to encourage tillering of cereals."],"sources":["Custom","NRCS (2017)"]}','core',1,2021,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.knife_roller','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Knife Roller"}',NULL,'{"descriptions":["Crushing, cutting and mixing effect on organic residues and cover crops. The implement reduces covering of the surface with organic residues by 10 %."],"sources":["KTBL (2020)"]}','core',1,2022,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.short_disk_harrow','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Short Disk Harrow"}',NULL,'{"descriptions":["Mixing, non-inversion stubble cultivation. The implement reduces covering of the surface with organic residues by 40-60 %."],"sources":["KTBL (2020)"]}','core',1,2023,0,'2026-07-12T00:00:00.000Z');
