INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.fine_cultivator','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Fine Cultivator"}',NULL,'{"descriptions":["Loosening and mixing, non-inversion stubble cultivation (shallow). The implement reduces covering of the surface with organic residues by 20-40 %. Also called chisel."],"sources":["KTBL (2020)"]}','core',1,2025,0,'2026-07-12T00:00:00.000Z');
