INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.direct_drill','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Direct Drill"}',NULL,'{"descriptions":["Seed placement in rows or bands with no prior tillage. Seed feed through dosing units and mechanical or pneumatic conveyance and distribution. Soil disturbance is not more than needed for seed and fertiliser placement. Sowing is carried out on less than 1/3 of the row width Cultivation depth is the seed placement depth."],"sources":["KTBL (2020)"]}','core',1,2028,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.direct_single_grain','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Direct Single Grain"}',NULL,'{"descriptions":["Seed placement is carried out without previous tillage. Seed placement in rows with defined longitudinal grain spacing at the defined placement depth. Seed feed through dosing units and mechanical or pneumatic conveyance and distribution. Sowing is carried out on less than 1/3 of the row width Cultivation depth is the seed placement depth."],"sources":["KTBL (2020)"]}','core',1,2029,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.classic_drill','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Classic Drill"}',NULL,'{"descriptions":["Seed placement in rows or bands at the defined placement depth. Seed feed through dosing units and mechanical or pneumatic conveyance and distribution."],"sources":["KTBL (2020)"]}','core',1,2030,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.classic_single_grain','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Classic Single Grain"}',NULL,'{"descriptions":["Seed placement in rows with defined longitudinal grain spacing at the defined placement depth. Seed feed through dosing units and mechanical or pneumatic conveyance and distribution."],"sources":["KTBL (2020)"]}','core',1,2031,0,'2026-07-12T00:00:00.000Z');
INSERT OR IGNORE INTO journal_vocab(code,kind,parent_code,value_type,quantity_kind,basis,default_unit_code,labels_json,icon_key,constraints_json,scope,active,sort_order,sync_version,created_at) VALUES ('agroscope.device.broadcast_seeder','choice','attr.agroscope.device',NULL,NULL,NULL,NULL,'{"en":"Broadcast Seeder"}',NULL,'{"descriptions":["Broadcast seeding is a method of seeding that involves scattering seed, by hand or mechanically, over a relatively large area."],"sources":["Custom"]}','core',1,2032,0,'2026-07-12T00:00:00.000Z');
