INSERT OR IGNORE INTO journal_layouts(code,version,labels_json,definition_json,active) VALUES ('agroscope_open_field',1,'{"en":"Agroscope open field"}','{"source":{"name":"SoilManageR management-data template","version":"2.6","date":"2024-12-23","license":"CC BY","attribution":"Wittwer, Heller, Turek — Agroscope"},"activity_codes":["tillage_soil_work","seeding","fertilization","plant_protection_application","harvest","irrigation","general_observation"],"supported_templates":["research_observation"],"fields":["attr.crop","attr.agroscope.operation","attr.agroscope.device","attr.amount_operation_depth","attr.amount_mass_area_product","attr.amount_volume_area_product","attr.amount_nutrient_rate","attr.amount_count_area","attr.amount_biological_count_area","attr.amount_duration_area","attr.irrigation_volume_area","attr.machine","attr.product","attr.agroscope.combination_group","attr.agroscope.dmc_mass_fraction","attr.agroscope.dmc_mass_volume","attr.agroscope.c_content","attr.agroscope.n_content","attr.agroscope.crop_product","attr.agroscope.crop_residue","attr.agroscope.cc_product","attr.agroscope.cc_residue"],"treatment_factors":{"plot_Parzelle":["I","II","III","IV","V","VI","all"],"tillage_system":["Plough","No-till","all"],"fertilization_regime":["GRUD","Kinsey","all"]},"option_dependencies":[{"source_category":"tillage","when":{"attribute_code":"activity_code","equals":"tillage_soil_work"},"restrict":{"attribute_code":"attr.agroscope.operation","choices":["agroscope.operation.primary_tillage","agroscope.operation.seedbed_preparation","agroscope.operation.stubble_cultivation"]}},{"source_category":"sowing","when":{"attribute_code":"activity_code","equals":"seeding"},"restrict":{"attribute_code":"attr.agroscope.operation","choices":["agroscope.operation.sowing_cover_crop","agroscope.operation.sowing_main_crop"]}},{"source_category":"fertilizer_application","when":{"attribute_code":"activity_code","equals":"fertilization"},"restrict":{"attribute_code":"attr.agroscope.operation","choices":["agroscope.operation.organic_fertilization","agroscope.operation.mineral_fertilization","agroscope.operation.other_fertilization"]}},{"source_category":"crop_protection","when":{"attribute_code":"activity_code","equals":"plant_protection_application"},"restrict":{"attribute_code":"attr.agroscope.operation","choices":["agroscope.operation.biocontrol","agroscope.operation.fungicide","agroscope.operation.insecticide","agroscope.operation.growth_regulator","agroscope.operation.weed_herbicide","agroscope.operation.total_herbicide","agroscope.operation.weed_mechanical","agroscope.operation.weed_other","agroscope.operation.pest_control"]}},{"source_category":"harvest","when":{"attribute_code":"activity_code","equals":"harvest"},"restrict":{"attribute_code":"attr.agroscope.operation","choices":["agroscope.operation.harvest_main_crop","agroscope.operation.harvest_cover_crop","agroscope.operation.hay_removal","agroscope.operation.straw_removal","agroscope.operation.cleaning_cut"]}},{"source_category":"irrigation","when":{"attribute_code":"activity_code","equals":"irrigation"},"restrict":{"attribute_code":"attr.agroscope.operation","choices":["agroscope.operation.watering"]}},{"source_category":"other","when":{"attribute_code":"activity_code","equals":"general_observation"},"restrict":{"attribute_code":"attr.agroscope.operation","choices":["agroscope.operation.sampling","agroscope.operation.note"]}},{"when":{"attribute_code":"attr.agroscope.operation","equals":"agroscope.operation.primary_tillage"},"restrict":{"attribute_code":"attr.agroscope.device","choices":["agroscope.device.plough","agroscope.device.plough_with_packer","agroscope.device.spading_machine","agroscope.device.deep_tiller","agroscope.device.heavy_duty_cultivator","agroscope.device.heavy_duty_cultivator_sweeps","agroscope.device.disk_harrow","agroscope.device.strip_tiller","agroscope.device.subsoiler","agroscope.device.paraplough","agroscope.device.separator","agroscope.device.skim_plough"]}